// ===========================================================================
// KNN Inference Functions
// ===========================================================================

static inline float knn_euclidean_distance(const float* a, const float* b) {
    float sum = 0.0f;
    for (uint16_t i = 0; i < 50; i++) {
        float d = a[i] - b[i];
        sum += d * d;
    }
    return sqrtf(sum);
}

static inline void knn_find_neighbors(const float* features, knn_neighbor_t* neighbors) {
    for (uint8_t k = 0; k < KNN_K; k++) {
        neighbors[k].distance = 1e30f;
        neighbors[k].label = 0;
    }

    for (uint16_t i = 0; i < 576; i++) {
        knn_sample_t sample;
        memcpy_P(&sample, &KNN_SAMPLES[i], sizeof(knn_sample_t));
        float dist = knn_euclidean_distance(features, sample.features);

        if (dist < neighbors[KNN_K - 1].distance) {
            neighbors[KNN_K - 1].distance = dist;
            neighbors[KNN_K - 1].label = sample.label;

            // Bubble up to maintain sorted order
            for (int8_t j = KNN_K - 2; j >= 0; j--) {
                if (neighbors[j + 1].distance < neighbors[j].distance) {
                    knn_neighbor_t tmp = neighbors[j];
                    neighbors[j] = neighbors[j + 1];
                    neighbors[j + 1] = tmp;
                } else {
                    break;
                }
            }
        }
    }
}

static inline uint8_t knn_predict(const float* features) {
    knn_neighbor_t neighbors[KNN_K];
    knn_find_neighbors(features, neighbors);

    uint16_t votes[5] = {0};
    for (uint8_t k = 0; k < KNN_K; k++) {
        if (neighbors[k].label < 5) {
            votes[neighbors[k].label]++;
        }
    }

    uint8_t best = 0;
    uint16_t maxVotes = 0;
    for (uint8_t i = 0; i < 5; i++) {
        if (votes[i] > maxVotes) {
            maxVotes = votes[i];
            best = i;
        }
    }
    return best;
}

static inline uint8_t knn_predict_with_confidence(const float* features, float* confidence) {
    knn_neighbor_t neighbors[KNN_K];
    knn_find_neighbors(features, neighbors);

    // Distance-weighted voting (matches trainer)
    float scores[5];
    memset(scores, 0, sizeof(scores));
    float totalWeight = 0.0f;

    for (uint8_t k = 0; k < KNN_K; k++) {
        float w = 1.0f / (neighbors[k].distance + 1e-5f);
        if (neighbors[k].label < 5) {
            scores[neighbors[k].label] += w;
            totalWeight += w;
        }
    }

    uint8_t best = 0;
    float maxScore = 0.0f;
    for (uint8_t i = 0; i < 5; i++) {
        if (scores[i] > maxScore) {
            maxScore = scores[i];
            best = i;
        }
    }

    *confidence = (totalWeight > 0.0f) ? (maxScore / totalWeight) : 0.0f;
    return best;
}

static inline const char* knn_get_class_name(uint8_t idx) {
    return (idx < 5) ? KNN_CLASS_NAMES[idx] : "unknown";
}

